    const uniqueDates = [
        ...new Set(sortedDates.map((d)=>d.getTime()))
    ].map((t)=>new Date(t)).sort((a, b)=>b.getTime() - a.getTime());
    if (uniqueDates.length === 0) {
        return {
            currentStreak: 0,
            longestStreak: 0,
            lastPostDate: null,
            isActiveToday: false
        };
    }
    const lastPostDate = uniqueDates[0];
    const isActiveToday = lastPostDate.getTime() === today.getTime();
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);
    // Calculate current streak
    let currentStreak = 0;
    let checkDate = isActiveToday ? today : yesterday;
    for (const date of uniqueDates){
        if (date.getTime() === checkDate.getTime()) {
            currentStreak++;
            checkDate = new Date(checkDate);
            checkDate.setDate(checkDate.getDate() - 1);
        } else if (date.getTime() < checkDate.getTime()) {
            break;
        }
    }
    // Calculate longest streak
    let longestStreak = 0;
    let tempStreak = 1;
    for(let i = 0; i < uniqueDates.length - 1; i++){
        const current = uniqueDates[i];
        const next = uniqueDates[i + 1];
        const diffDays = Math.round((current.getTime() - next.getTime()) / (1000 * 60 * 60 * 24));
        if (diffDays === 1) {
            tempStreak++;
        } else {
            longestStreak = Math.max(longestStreak, tempStreak);
            tempStreak = 1;
        }
    }
    longestStreak = Math.max(longestStreak, tempStreak);
    return {
        currentStreak,
        longestStreak,
        lastPostDate: lastPostDate.toISOString(),
        isActiveToday
    };
